protected PurchRFQSendTmp initializeRequestForQuotationLine(
    VendRFQTrans    _vendRFQTrans,
    VendRFQJour     _vendRFQJour,
    EcoResCategory  _ecoResCategory)
{
    next initializeRequestForQuotationLine(_vendRFQTrans, _vendRFQJour, _ecoResCategory);

    FWFTextBlockReportTextInit textBlockReportTextInit = FWFTextBlockReportTextInit::newParameters(tmpPurchRFQSend, _vendRFQJour);

    textBlockReportTextInit.insTexts();
    textBlockReportTextInit.parmSource(_vendRFQTrans);
    textBlockReportTextInit.insLineTexts();

    return tmpPurchRFQSend;
}
